<?php $game=isset($data['game'])&&is_array($data['game'])?$data['game']:['slug'=>'plinko','name'=>'Plinko','probability'=>['summary'=>'Each drop follows a server-generated path through the configured peg board.','theoretical_return'=>'Configured by the current public paytable.'],'paytable'=>[]]; $prob=is_array($game['probability']??null)?$game['probability']:[]; $paytable=is_array($game['paytable']??null)?$game['paytable']:[]; ?>
<header class="page-hero"><div class="shell page-hero-inner"><nav class="breadcrumbs" aria-label="Breadcrumb"><a href="<?= $url('probabilities.index', [], '/probabilities') ?>">Probabilities</a><span aria-hidden="true">/</span><span><?= $esc($game['name']) ?></span></nav><p class="eyebrow">Public probability disclosure</p><h1><?= $esc($game['name']) ?></h1><p class="lede"><?= $esc((string)($prob['summary']??'The server generates outcomes according to the published rules and current configuration.')) ?></p></div></header>
<section class="section shell article-layout"><nav class="article-nav" aria-label="On this page"><a href="#summary">Summary</a><a href="#paytable">Paytable</a><a href="#return">Theoretical return</a><a href="#verification">Outcome verification</a></nav><article class="prose"><h2 id="summary">Probability summary</h2><p><?= $esc((string)($prob['details']??$prob['summary']??'Outcome probabilities are calculated from the current game configuration.')) ?></p><?php if(!empty($prob['outcomes'])&&is_array($prob['outcomes'])): ?><table><thead><tr><th>Outcome</th><th>Probability</th></tr></thead><tbody><?php foreach($prob['outcomes'] as $row): ?><tr><td><?= $esc((string)($row['label']??'')) ?></td><td><?= $esc((string)($row['probability']??'')) ?></td></tr><?php endforeach; ?></tbody></table><?php endif; ?><h2 id="paytable">Current paytable</h2><?php if($paytable): ?><table><thead><tr><th>Outcome</th><th>Fictional payout</th></tr></thead><tbody><?php foreach($paytable as $row): ?><tr><td><?= $esc((string)($row['label']??$row[0]??'')) ?></td><td><?= $esc((string)($row['payout']??$row[1]??'')) ?></td></tr><?php endforeach; ?></tbody></table><?php else: ?><p>The live server provides the current configured paytable here before any fictional wager is accepted.</p><?php endif; ?><h2 id="return">Theoretical return</h2><p><?= $esc((string)($prob['theoretical_return']??'See the current server configuration.')) ?></p><p>This figure is a long-run expectation, not a promise. Different users and membership levels use the same outcome rules.</p><h2 id="verification">Reproducible outcome verification</h2><p>Where supported, the Parlor publishes a server-seed hash before play and reveals a rotated seed later. This lets you reproduce an outcome using the documented client seed and nonce without exposing a current secret seed.</p><a href="<?= $url('fairness.verify', [], '/fairness/verify') ?>">Open verification tool</a></article></section>
